class Solution:
    def passwordStrength(self, password: str) -> int:
        seen = set(password)
        total = 0
        for ch in seen:
            if ch.islower():
                total += 1
            elif ch.isupper():
                total += 2
            elif ch.isdigit():
                total += 3
            elif ch in "!@#$":
                total += 5
        return total

