var passwordStrength = function(password) {
    const seen = new Set(password);
    let total = 0;
    for (const ch of seen) {
        if (ch >= 'a' && ch <= 'z') total += 1;
        else if (ch >= 'A' && ch <= 'Z') total += 2;
        else if (ch >= '0' && ch <= '9') total += 3;
        else if ('!@#$'.includes(ch)) total += 5;
    }
    return total;
};
